import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        StringBuilder buffer = new StringBuilder(); // Use StringBuilder for dynamic resizing

        // Copy user input into the buffer
        buffer.append(input);

        System.out.println("Input successfully copied into buffer: " + buffer.toString());
    }
}

